        void 0 == a;
        void 0 != a;
        void 0 === a;
        void 0 !== a""".stripMargin.trim,
      expected = """a == null;
        a != null;
        a === void 0;
        a !== void 0;

        null == a;
        null != a;
        void 0 === a;
        void 0 !== a;

        null == a;
        null != a;
        void 0 === a;
        void 0 !== a""".stripMargin.trim,
      options = AllOff.copy(
        comparisons = true
      )
    )
  }

